lesson_css:
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

  :root {
    --green: #53a318;
    --green-dark: #3f7d12;
    --green-light: #eef6e7;
    --ink: #1d2b12;
    --muted: #5c6b50;
    --line: #e2e8da;
    --card: #ffffff;
    --bg: #f6f8f3;
    --pill-deck-fg:#5a4dc7;   --pill-deck-bg:#efeefb;
    --pill-quiz-fg:#c75a7a;   --pill-quiz-bg:#fbeef2;
    --pill-video-fg:#1e7898;  --pill-video-bg:#e8f3f8;
    --pill-notes-fg:#5a6275;  --pill-notes-bg:#eef0f3;
    --pill-playbook-fg:#b85a1f; --pill-playbook-bg:#fbf0e8;
    --pill-guide-fg:#3d7a11;  --pill-guide-bg:#f0f6e8;
    --pill-tools-fg:#8a4cc4;  --pill-tools-bg:#f3ecfa;
    --pill-module-fg:#1e6898; --pill-module-bg:#e8f1f8;
    --pill-exercise-fg:#b85a1f; --pill-exercise-bg:#fbf0e8;
    --pill-roleplay-fg:#8a4cc4; --pill-roleplay-bg:#f3ecfa;
    --pill-examples-fg:#5a6275; --pill-examples-bg:#eef0f3;
  }

  .link-pill{display:inline-flex;align-items:center;gap:4px;font-size:11px;font-weight:600;padding:4px 11px;border-radius:999px;text-decoration:none;border:1px solid transparent;letter-spacing:.005em;margin-right:6px;margin-top:4px}
  .link-pill:hover{filter:brightness(.93)}
  .link-pill.deck{color:var(--pill-deck-fg);background:var(--pill-deck-bg)}
  .link-pill.quiz{color:var(--pill-quiz-fg);background:var(--pill-quiz-bg)}
  .link-pill.video{color:var(--pill-video-fg);background:var(--pill-video-bg)}
  .link-pill.notes{color:var(--pill-notes-fg);background:var(--pill-notes-bg)}
  .link-pill.playbook{color:var(--pill-playbook-fg);background:var(--pill-playbook-bg)}
  .link-pill.guide{color:var(--pill-guide-fg);background:var(--pill-guide-bg)}
  .link-pill.tools{color:var(--pill-tools-fg);background:var(--pill-tools-bg)}
  .link-pill.module{color:var(--pill-module-fg);background:var(--pill-module-bg)}
  .link-pill.exercise{color:var(--pill-exercise-fg);background:var(--pill-exercise-bg)}
  .link-pill.roleplay{color:var(--pill-roleplay-fg);background:var(--pill-roleplay-bg)}
  .link-pill.examples{color:var(--pill-examples-fg);background:var(--pill-examples-bg)}

  .embed-box{position:relative;width:100%;background:#1a1f2c;border-radius:10px;overflow:hidden;margin:12px 0;aspect-ratio:16/9;max-height:480px}
  .embed-box iframe{position:absolute;inset:0;width:100%;height:100%;border:0}
  .embed-call{aspect-ratio:auto;height:62px;max-height:62px;background:#eef2f7}
  .embed-call-sm{aspect-ratio:auto;height:50px;max-height:50px;background:#eef2f7;margin:4px 0 10px}
  .call-caption{font-size:12px;color:var(--muted);margin:0 0 2px}
  .call-caption strong{color:var(--ink,#1a1f2c)}
  .listen-label{display:inline-flex;align-items:center;gap:6px;font-size:13px;font-weight:700;color:var(--green-dark);margin:8px 0 2px}
  .call-cat{display:inline-block;font-size:12px;font-weight:800;letter-spacing:.04em;text-transform:uppercase;color:#fff;background:var(--green);padding:2px 9px;border-radius:4px;margin:12px 0 2px}
  .call-player{border:1px solid #d9e3cf;border-radius:8px;background:#fff;margin:6px 0 10px;overflow:hidden}
  .call-player>summary{list-style:none;cursor:pointer;display:flex;align-items:center;gap:8px;padding:9px 12px}
  .call-player>summary::-webkit-details-marker{display:none}
  .call-player>summary:hover{background:#f6faf1}
  .cp-icon{font-size:15px;line-height:1}
  .cp-play{font-weight:700;font-size:13px;color:var(--green-dark);white-space:nowrap}
  .cp-play::before{content:"\25B6  Play recording"}
  .call-player[open] .cp-play::before{content:"\25BC  Hide player"}
  .cp-meta{font-size:12px;color:var(--muted)}
  .cp-meta strong{color:var(--ink)}
  .call-player[open]>summary{border-bottom:1px solid #eef2f7}
  .call-player .embed-call-sm{margin:0;background:#fff}

  .exercise-prompt { margin: 10px 0 4px; }
  .exercise-prompt .ep-task { font-size: 13px; font-weight: 600; color: var(--ink); margin-bottom: 6px; }
  .exercise-prompt ul { margin: 0; padding-left: 18px; }
  .exercise-prompt li { font-size: 13px; color: var(--muted); padding: 2px 0; }

  .gc-list { margin: 6px 0 10px; padding-left: 18px; }
  .gc-list li { font-size: 13px; color: var(--muted); padding: 3px 0; }
  .gc-list a { color: var(--green-dark); text-decoration: none; font-weight: 600; }
  .gc-list a:hover { text-decoration: underline; }
  .card-links { margin-top: 6px; }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Inter', system-ui, sans-serif;
    color: var(--ink);
    background: var(--bg);
    line-height: 1.5;
    padding: 0;
  }

  .wrap { max-width: 1100px; margin: 0 auto; padding: 28px 20px 60px; }

  /* ---------- Header ---------- */
  .masthead {
    background: linear-gradient(135deg, var(--green) 0%, var(--green-dark) 100%);
    color: #fff;
    border-radius: 16px;
    padding: 30px 32px;
    margin-bottom: 22px;
  }
  .masthead .eyebrow {
    text-transform: uppercase;
    letter-spacing: 2px;
    font-size: 12px;
    font-weight: 600;
    opacity: 0.85;
  }
  .masthead h1 { font-size: 30px; font-weight: 800; margin: 6px 0 8px; }
  .masthead p { font-size: 15px; opacity: 0.92; max-width: 640px; }

  /* ---------- Week switcher ---------- */
  .week-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-bottom: 18px;
  }
  .week-btn {
    cursor: pointer;
    padding: 10px 22px;
    border-radius: 999px;
    border: 1px solid var(--line);
    background: var(--card);
    font-size: 14px;
    font-weight: 700;
    color: var(--muted);
    user-select: none;
    transition: all 0.15s ease;
  }
  .week-btn:hover { border-color: var(--green); color: var(--green-dark); }
  #wk1:checked ~ .week-bar label[for="wk1"],
  #wk2:checked ~ .week-bar label[for="wk2"],
  #wk3:checked ~ .week-bar label[for="wk3"],
  #wk4:checked ~ .week-bar label[for="wk4"] { background: var(--green-dark); border-color: var(--green-dark); color: #fff; }
  .nav-radio, .day-radio { position: absolute; left: -9999px; width: 1px; height: 1px; opacity: 0; }
  .week-btn { cursor: pointer; }

  /* ===== Vertical toggle ===== */
  .vert-radio { position: absolute; left: -9999px; opacity: 0; }
  .vertical-section { display: none; }
  #vert-hbw:checked ~ [data-vertical-section="hbw"] { display: block; }
  #vert-ttd:checked ~ [data-vertical-section="ttd"] { display: block; }
  #vert-fd:checked ~ [data-vertical-section="fd"] { display: block; }
  #vert-ha:checked ~ [data-vertical-section="ha"] { display: block; }
  .vertical-bar { display: flex; gap: 10px; flex-wrap: wrap; margin: 0 0 22px; }
  .vertical-btn { cursor: pointer; padding: 12px 22px; border-radius: 10px; border: 2px solid var(--green); background: #fff; color: var(--green-dark); font-weight: 800; font-size: 15px; letter-spacing: .2px; }
  .vertical-btn:hover { background: #f2f8ec; }
  #vert-hbw:checked ~ .vertical-bar .vertical-btn[for="vert-hbw"] { background: var(--green); color: #fff; border-color: var(--green); }
  #vert-ttd:checked ~ .vertical-bar .vertical-btn[for="vert-ttd"] { background: var(--green); color: #fff; border-color: var(--green); }
  #vert-fd:checked ~ .vertical-bar .vertical-btn[for="vert-fd"] { background: var(--green); color: #fff; border-color: var(--green); }
  #vert-ha:checked ~ .vertical-bar .vertical-btn[for="vert-ha"] { background: var(--green); color: #fff; border-color: var(--green); }
  .week-section { display: none; }
  #hbw-wk1:checked ~ [data-week-section="1"],
  #hbw-wk2:checked ~ [data-week-section="2"],
  #hbw-wk3:checked ~ [data-week-section="3"],
  #hbw-wk4:checked ~ [data-week-section="4"] { display: block; }
  #ttd-wk1:checked ~ [data-week-section="1"],
  #ttd-wk2:checked ~ [data-week-section="2"],
