  /* ---------- Day Tabs ---------- */
  .tab-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-bottom: 22px;
  }
  .tab {
    cursor: pointer;
    flex: 1 1 150px;
    min-width: 130px;
    background: var(--card);
    border: 1px solid var(--line);
    border-radius: 12px;
    padding: 14px 16px;
    transition: all 0.18s ease;
    user-select: none;
  }
  .tab:hover { border-color: var(--green); transform: translateY(-2px); }
  .tab .daynum {
    font-size: 12px;
    font-weight: 600;
    color: var(--muted);
    text-transform: uppercase;
    letter-spacing: 1px;
  }
  .tab .daytitle { font-size: 16px; font-weight: 700; margin-top: 2px; }
