  .day-head {
    display: flex;
    align-items: center;
    gap: 16px;
    margin-bottom: 20px;
  }
  .day-badge {
    width: 56px; height: 56px;
    border-radius: 14px;
    background: var(--green-light);
    color: var(--green-dark);
    font-size: 22px;
    font-weight: 800;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .day-head h2 { font-size: 22px; font-weight: 800; }
  .day-head .sub { color: var(--muted); font-size: 14px; }

  /* ---------- Resource cards ---------- */
  .section-label {
    font-size: 12px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--green-dark);
    margin: 24px 0 12px;
  }
  .res-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(260px, 1fr)); gap: 14px; }
  .res-grid.single { grid-template-columns: 1fr; }

  .res-card {
    background: var(--card);
    border: 1px solid var(--line);
    border-left: 4px solid var(--green);
    border-radius: 12px;
    padding: 16px 18px;
  }
  .res-card .type {
    display: inline-block;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--green-dark);
    background: var(--green-light);
    padding: 3px 8px;
    border-radius: 6px;
    margin-bottom: 8px;
  }
  .res-card .time-pill {
    display: inline-block;
    font-size: 11px;
    font-weight: 700;
    color: #fff;
    background: var(--green-dark);
    padding: 3px 9px;
    border-radius: 20px;
    margin-bottom: 8px;
    margin-left: 6px;
    white-space: nowrap;
  }
  .cert-req { display:inline-block; font-size:11px; font-weight:700; color:#92400e; background:#fde9b8; border:1px solid #e0a92e; padding:3px 9px; border-radius:20px; margin-bottom:8px; margin-left:6px; white-space:nowrap; vertical-align:middle; }
  .cat-merge .cert-req { margin:2px 0 6px 0; }
  .res-card h4 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
  .res-card p { font-size: 13px; color: var(--muted); margin-bottom: 10px; }
  .res-card a {
    font-size: 13px;
    font-weight: 600;
    color: var(--green-dark);
    text-decoration: none;
  }
  .res-card a:hover { text-decoration: underline; }
  .placeholder { color: #aab3a0; font-style: italic; }

  .checklist { list-style: none; }
  .checklist li {
    padding: 9px 0 9px 30px;
    position: relative;
    border-bottom: 1px solid var(--line);
    font-size: 14px;
  }
  .checklist li:last-child { border-bottom: none; }
  .checklist li::before {
    content: "";
    position: absolute;
    left: 4px; top: 11px;
    width: 16px; height: 16px;
    border: 2px solid var(--green);
    border-radius: 5px;
  }

  /* ---------- Day 1 timeline / stages ---------- */
  .stage {
    background: var(--card);
    border: 1px solid var(--line);
    border-radius: 14px;
    padding: 0;
    margin-bottom: 16px;
    overflow: hidden;
  }
  .stage-head {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 16px 20px;
    background: var(--green-light);
    border-bottom: 1px solid var(--line);
  }
  .stage-time {
    flex-shrink: 0;
    font-size: 12px;
    font-weight: 700;
    color: #fff;
    background: var(--green-dark);
    padding: 5px 10px;
    border-radius: 20px;
    letter-spacing: 0.5px;
    white-space: nowrap;
  }
  .stage-head h3 { font-size: 17px; font-weight: 800; color: var(--ink); }
  .stage-head .owner { font-size: 12px; font-weight: 600; color: var(--muted); text-transform: uppercase; letter-spacing: 0.5px; }
  .stage-body { padding: 18px 20px; }
  .stage-body > p.lead { font-size: 14px; color: var(--muted); margin-bottom: 14px; }
  .stage-body .res-grid { margin-top: 4px; }

  /* ---------- Scenario quiz (Day 2 debrief) ---------- */
  .scenario {
    background: var(--card);
    border: 1px solid var(--line);
    border-radius: 10px;
    margin-bottom: 10px;
    overflow: hidden;
  }
  .scenario summary {
    cursor: pointer;
    padding: 14px 18px;
    font-size: 14px;
    font-weight: 600;
    list-style: none;
    display: flex;
    align-items: flex-start;
    gap: 10px;
  }
  .scenario summary::-webkit-details-marker { display: none; }
  .scenario summary::before {
    content: "?";
    flex-shrink: 0;
    width: 22px; height: 22px;
    background: var(--green-light);
    color: var(--green-dark);
    border-radius: 50%;
    font-weight: 800;
    font-size: 13px;
    display: flex; align-items: center; justify-content: center;
  }
  .scenario[open] summary { border-bottom: 1px solid var(--line); }
  .scenario[open] summary::before { content: "\2713"; background: var(--green); color: #fff; }
  .scenario .answer {
    padding: 14px 18px 16px 50px;
    font-size: 13px;
    color: var(--muted);
  }
  .scenario .answer strong { color: var(--green-dark); }

  .note {
    background: #fffaf0;
