  /* checklist (Week 2 Wed–Fri) */
  .cl-head { font-size: 13px; font-weight: 800; text-transform: uppercase; letter-spacing: .5px; color: var(--green-dark); margin: 20px 0 10px; }
  .check { display: flex; align-items: flex-start; gap: 12px; padding: 12px 14px; border: 1px solid var(--line); border-radius: 10px; background: var(--card); cursor: pointer; transition: border-color .15s ease; margin-bottom: 8px; }
  .check:hover { border-color: var(--green); }
  .check input { margin: 2px 0 0; width: 18px; height: 18px; accent-color: var(--green); flex: none; cursor: pointer; }
  .check input:checked + span { text-decoration: line-through; color: var(--muted); }
  .check span { font-size: 15px; line-height: 1.4; }
  .goal-banner { display: flex; gap: 14px; align-items: flex-start; background: var(--green-light); border: 1px solid var(--green); border-radius: 12px; padding: 16px 18px; margin-bottom: 8px; }
  .goal-banner .g-icon { font-size: 24px; line-height: 1; }
  .goal-banner .g-title { font-weight: 800; color: var(--green-dark); font-size: 13px; text-transform: uppercase; letter-spacing: .5px; margin-bottom: 6px; }
  .goal-banner .check { background: #fff; }
  .habit { display: flex; align-items: flex-start; gap: 12px; padding: 12px 14px; border: 1px solid var(--line); border-left: 4px solid var(--green); border-radius: 10px; background: var(--card); margin-bottom: 8px; }
  .habit .tag { font-size: 10px; font-weight: 800; text-transform: uppercase; letter-spacing: .5px; color: #fff; background: var(--green); padding: 3px 7px; border-radius: 6px; flex: none; margin-top: 1px; }
  .habit .h-txt { font-size: 15px; line-height: 1.4; }
  .milestone { display: flex; gap: 16px; align-items: flex-start; border: 1px solid var(--line); border-left: 4px solid var(--green); border-radius: 12px; padding: 18px 20px; margin-bottom: 14px; background: var(--card); }
  .milestone .m-badge { flex: none; min-width: 72px; text-align: center; background: var(--green-light); color: var(--green-dark); border-radius: 10px; padding: 12px 8px; font-weight: 800; }
  .milestone .m-badge .m-wk { font-size: 11px; text-transform: uppercase; letter-spacing: .5px; display: block; }
  .milestone .m-badge .m-no { font-size: 24px; display: block; line-height: 1.1; }
  .milestone .m-body { flex: 1; }
  .milestone.final { border-left-color: #f59e0b; }
  .milestone.final .m-badge { background: #fef3c7; color: #b45309; }
